import{c as t,Q as a,j as i,m as s}from"./chunks/framework.C1Tv9fGx.js";const u=JSON.parse('{"title":"Artifact types","description":"","frontmatter":{"title":"Artifact types","outline":[2,3]},"headers":[],"relativePath":"reference/artifact-types.md","filePath":"reference/artifact-types.md","lastUpdated":1779171375000}'),o={name:"reference/artifact-types.md"};function n(r,e,l,d,c,p){return a(),i("div",null,[...e[0]||(e[0]=[s(`<h1 id="artifact-types" tabindex="-1">Artifact Types <a class="header-anchor" href="#artifact-types" aria-label="Permalink to &quot;Artifact Types&quot;">​</a></h1><p>Every NL programming artifact NLPM scores. Each row in a report&#39;s <em>type</em> column maps to one section below.</p><h2 id="artifact-skill-md-cross-tool-open-standard" tabindex="-1">SKILL.md — Cross-Tool Open Standard <a class="header-anchor" href="#artifact-skill-md-cross-tool-open-standard" aria-label="Permalink to &quot;SKILL.md — Cross-Tool Open Standard {#artifact-skill-md-cross-tool-open-standard}&quot;">​</a></h2><p>SKILL.md is the <strong>Agent Skills open spec</strong>, stewarded by the Agentic AI Foundation under the Linux Foundation. Anthropic published the spec on 2025-12-18; OpenAI, Microsoft, Google adopted within 48 hours. By 2026-03, 32+ tools read the same SKILL.md format (Claude Code, Codex, Gemini CLI / Antigravity, Cursor, Kiro, Continue, etc.).</p><p><strong>Authoritative reference:</strong> <a href="https://agentskills.io/specification" target="_blank" rel="noreferrer">https://agentskills.io/specification</a></p><p><strong>Required frontmatter (per the open spec):</strong></p><ul><li><code>name</code> — string; 1-64 chars, lowercase + hyphens only, <strong>MUST match parent directory name</strong> (no leading/trailing/consecutive hyphens).</li><li><code>description</code> — string; 1-1024 chars; should describe what the skill does AND when to use it.</li></ul><p><strong>Optional frontmatter (per the open spec):</strong></p><ul><li><code>license</code> — license name or reference to a bundled file.</li><li><code>compatibility</code> — environment requirements, max 500 chars (e.g., &quot;Designed for Claude Code&quot;, &quot;Requires Python 3.14+ and uv&quot;).</li><li><code>metadata</code> — arbitrary key-value mapping (<code>author</code>, <code>version</code>, etc. go here, NOT as top-level fields).</li><li><code>allowed-tools</code> — space-separated tool list (experimental in spec; tool-specific in practice — e.g., <code>Bash(git:*) Read</code>).</li></ul><p><strong>Tool-specific extensions to SKILL.md frontmatter</strong> live in the per-tool overlay skills. The scorer applies the universal spec rules to ALL SKILL.md files. Tool-specific overlay rules apply ONLY to files at the matching tool&#39;s canonical paths.</p><p><strong>Skill paths (canonical, per tool):</strong></p><table tabindex="0"><thead><tr><th>Tool</th><th>Path</th></tr></thead><tbody><tr><td>Open-spec (cross-tool)</td><td><code>.agents/skills/&lt;name&gt;/SKILL.md</code></td></tr><tr><td>Claude Code</td><td><code>.claude/skills/&lt;name&gt;/SKILL.md</code></td></tr><tr><td>Codex CLI</td><td><code>.agents/skills/&lt;name&gt;/SKILL.md</code></td></tr><tr><td>Antigravity</td><td><code>&lt;workspace&gt;/.agent/skills/&lt;name&gt;/SKILL.md</code> (singular) AND <code>.agents/skills/&lt;name&gt;/SKILL.md</code> (cross-tool alias)</td></tr><tr><td>Gemini CLI (legacy)</td><td><code>.gemini/skills/&lt;name&gt;/SKILL.md</code></td></tr><tr><td>Continue, Cursor, Kiro</td><td><code>.&lt;tool&gt;/skills/&lt;name&gt;/SKILL.md</code></td></tr></tbody></table><p><strong>Body rules (recommendations, not spec requirements):</strong></p><ul><li>Keep under 500 lines — exceeding creates context bloat (spec recommends under 5000 tokens for the body, with overflow in <code>references/</code>).</li><li>Reference material — imperatives belong in commands/agents.</li><li>Include a scope note: what this skill covers and what it does NOT cover.</li><li>Cross-reference related skills with their <code>plugin:skill</code> identifiers.</li></ul><p>The spec explicitly says &quot;no format restrictions&quot; on the body — do NOT penalize SKILL.md files for missing <code>## Output</code> or other section conventions. Those are tool-specific style preferences, not spec violations.</p><p><strong>Supporting directories (per the spec):</strong></p><ul><li><code>scripts/</code> — executable code (Python, Bash, JavaScript)</li><li><code>references/</code> — additional docs loaded on demand</li><li><code>assets/</code> — templates, images, data files</li></ul><p><strong>Progressive disclosure:</strong></p><ol><li>Metadata (~100 tokens): name + description loaded at startup for ALL skills.</li><li>Instructions (&lt;5000 tokens): full SKILL.md body loaded when activated.</li><li>Resources: scripts/references/assets loaded only when needed.</li></ol><hr><h2 id="artifact-agents-md-canonical-universal-memory-file" tabindex="-1">AGENTS.md — Canonical Universal Memory File <a class="header-anchor" href="#artifact-agents-md-canonical-universal-memory-file" aria-label="Permalink to &quot;AGENTS.md — Canonical Universal Memory File {#artifact-agents-md-canonical-universal-memory-file}&quot;">​</a></h2><p>Per nlpm decision (<code>analysis/multi-tool-design-2026-05.md</code> §5), AGENTS.md is the canonical universal memory file across all tools nlpm supports.</p><p><strong>Tool-native support:</strong></p><ul><li><strong>Codex CLI:</strong> reads AGENTS.md natively. Hierarchical (root→cwd; closer overrides earlier). 32 KiB cap. <code>~/.codex/AGENTS.override.md</code> for personal overlays.</li><li><strong>Antigravity (and Gemini CLI):</strong> reads <code>GEMINI.md</code> natively, but <code>context.fileName</code> setting accepts an array — set to <code>[&quot;AGENTS.md&quot;, &quot;GEMINI.md&quot;]</code> to make it read AGENTS.md.</li><li><strong>Claude Code:</strong> reads <code>CLAUDE.md</code> natively, supports <code>@file.md</code> import syntax. The canonical pattern is a one-line <code>CLAUDE.md</code> containing <code>@AGENTS.md</code>.</li></ul><p><strong>Recommended pattern for multi-tool projects:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>project-root/</span></span>
<span class="line"><span>├── AGENTS.md           # canonical content — all instructions live here</span></span>
<span class="line"><span>├── CLAUDE.md           # one line: @AGENTS.md</span></span>
<span class="line"><span>├── GEMINI.md           # one line: @AGENTS.md  (only if Gemini-native @-import works)</span></span>
<span class="line"><span>└── .gemini/settings.json  # set context.fileName: [&quot;AGENTS.md&quot;]</span></span></code></pre></div><p>This is exactly how nlpm itself is structured (<code>CLAUDE.md</code> → <code>@AGENTS.md</code>).</p><p><strong>Body conventions</strong> (universal):</p><ul><li>Open with a one-line project description.</li><li><code>## Architecture</code> or <code>## Project Structure</code> — what lives where.</li><li><code>## Build</code> / <code>## Run</code> / <code>## Test</code> — verifiable commands.</li><li><code>## Prerequisites</code> — required tools / versions / setup.</li><li><code>## Conventions</code> — naming, style, patterns.</li></ul><p><strong>Tool-specific memory-file extensions</strong> (e.g., Claude Code&#39;s <code>@</code>-import syntax, Gemini&#39;s <code>@{path}</code> injection, Codex&#39;s <code>project_doc_fallback_filenames</code>) live in the per-tool overlays.</p><h3 id="agent-workflow-programs-recognized-variant-no-penalty-rubric-yet" tabindex="-1">Agent workflow programs (recognized variant, no penalty rubric yet) <a class="header-anchor" href="#agent-workflow-programs-recognized-variant-no-penalty-rubric-yet" aria-label="Permalink to &quot;Agent workflow programs (recognized variant, no penalty rubric yet)&quot;">​</a></h3><p>Some repos ship a single project-root Markdown file that drives an autonomous agent loop — imperative numbered steps with output formats and error paths, sitting between a memory file (AGENTS.md-shaped context) and a slash command (workflow with verifiable side effects). Karpathy&#39;s <code>program.md</code> in <a href="https://github.com/karpathy/autoresearch" target="_blank" rel="noreferrer"><code>karpathy/autoresearch</code></a> is the canonical example (audited 2026-05-28 at score ~90; see <a href="./../../../auditor/exemplars/karpathy-autoresearch"><code>auditor/exemplars/karpathy-autoresearch.md</code></a>). The README explicitly frames it as natural-language programming: &quot;you are programming the <code>program.md</code> Markdown files that provide context to the AI agents.&quot;</p><p>nlpm recognizes the pattern but does not yet have a dedicated penalty rubric — the universal floor (R01 vague quantifiers, R03 positive framing, R09 prompt layers) + the command rules (R14–R17) + the memory-file rules (R33–R39) cover it adequately as a hybrid. A standalone rubric is deferred until N≥3 examples surface, per the same &quot;don&#39;t build for an empty corpus&quot; discipline applied to multi-tool discovery.</p><hr><h2 id="artifact-general-prompt-engineering" tabindex="-1">General Prompt Engineering <a class="header-anchor" href="#artifact-general-prompt-engineering" aria-label="Permalink to &quot;General Prompt Engineering {#artifact-general-prompt-engineering}&quot;">​</a></h2><p>Universal patterns applicable to any NL artifact (commands, agents, skills, prompts) regardless of tool.</p><p><strong>Layer order</strong> (imperative for complex prompts):</p><ol><li>Role/persona — &quot;You are a strict code reviewer...&quot;</li><li>Context — project state, prior decisions, file paths, constraints</li><li>Task — specific action to perform</li><li>Constraints — what to avoid, limits, edge cases</li><li>Output format — exact structure of the response</li></ol><p><strong>Few-shot examples:</strong> Include 2+ concrete input→output examples for any complex judgment task. Examples dramatically improve consistency.</p><p><strong>Positive framing:</strong> State what to do. &quot;Use imperative verbs&quot; beats &quot;Don&#39;t use passive voice.&quot; The brain processes prohibitions poorly under inference load (Pink Elephant effect).</p><p><strong>Explicit output format:</strong> Every command and agent body should define exactly what the output should look like — section names, table formats, score displays, etc.</p><hr><h2 id="artifact-vague-quantifiers-r01" tabindex="-1">Vague Quantifiers (R01) <a class="header-anchor" href="#artifact-vague-quantifiers-r01" aria-label="Permalink to &quot;Vague Quantifiers (R01) {#artifact-vague-quantifiers-r01}&quot;">​</a></h2><p>The R01 rule penalizes unbounded quantifiers without measurable criteria. The penalty applies regardless of which tool the artifact targets.</p><p><strong>Penalized terms:</strong> <code>appropriate</code>, <code>relevant</code>, <code>as needed</code>, <code>sufficient</code>, <code>adequate</code>, <code>reasonable</code>, <code>properly</code>, <code>correctly</code>, <code>some</code>, <code>several</code>, <code>various</code>.</p><p><strong>Carve-outs (do NOT penalize):</strong></p><ul><li><code>relevant</code> in a markdown header (e.g., <code>## Relevant X</code>).</li><li><code>relevant to &lt;named-scope&gt;</code> constructions (semantic &quot;pertinent to&quot;).</li><li>Any term followed by a measurable criterion clause (e.g., &quot;appropriate to the SLO target of 99.9% uptime&quot;).</li></ul><p>See <code>nlpm:scoring</code> for the full vague-quantifier penalty table and cap (-2 each, -20 cap).</p><hr><h2 id="artifact-naming-conventions-universal" tabindex="-1">Naming Conventions (universal) <a class="header-anchor" href="#artifact-naming-conventions-universal" aria-label="Permalink to &quot;Naming Conventions (universal) {#artifact-naming-conventions-universal}&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Item</th><th>Convention</th><th>Example</th></tr></thead><tbody><tr><td>File names</td><td>kebab-case</td><td><code>tdd-guardian.md</code>, <code>pre-write-check.sh</code></td></tr><tr><td>Plugin/package names</td><td>kebab-case</td><td><code>nlpm</code>, <code>echo-sleuth</code></td></tr><tr><td>Skill references</td><td><code>plugin-name:skill-name</code></td><td><code>nlpm:conventions</code>, <code>tdd-guardian:rules</code></td></tr><tr><td>Rule files (ordered)</td><td><code>NN-kebab.md</code></td><td><code>01-formatting.md</code></td></tr><tr><td>Environment variables</td><td>SCREAMING_SNAKE</td><td><code>OPENAI_API_KEY</code>, <code>CLAUDE_PLUGIN_ROOT</code></td></tr><tr><td>Plugin directory env vars</td><td><code>&lt;TOOL&gt;_PLUGIN_ROOT</code></td><td><code>CLAUDE_PLUGIN_ROOT</code>, <code>CODEX_PLUGIN_ROOT</code></td></tr></tbody></table><p><strong>Portable paths:</strong> Within a plugin, always reference files via the tool&#39;s plugin-root environment variable (e.g., <code>\${CLAUDE_PLUGIN_ROOT}</code> for Claude, equivalent for Codex). Hardcoded absolute paths break portability.</p><p>Tool-specific naming details (e.g., the exact <code>CLAUDE_PLUGIN_ROOT</code> semantics) live in the per-tool overlays.</p><hr><h2 id="artifact-rule-overrides-claude-nlpm-local-md-or-equivalent" tabindex="-1">Rule Overrides (<code>.claude/nlpm.local.md</code> or equivalent) <a class="header-anchor" href="#artifact-rule-overrides-claude-nlpm-local-md-or-equivalent" aria-label="Permalink to &quot;Rule Overrides (\`.claude/nlpm.local.md\` or equivalent) {#artifact-rule-overrides-claude-nlpm-local-md-or-equivalent}&quot;">​</a></h2><p>The override system is universal. The configuration file path is per-tool:</p><table tabindex="0"><thead><tr><th>Tool</th><th>Config path</th></tr></thead><tbody><tr><td>Claude Code</td><td><code>.claude/nlpm.local.md</code></td></tr><tr><td>Codex CLI</td><td><code>.codex/nlpm.local.md</code></td></tr><tr><td>Antigravity</td><td><code>.gemini/nlpm.local.md</code> (or <code>.agent/nlpm.local.md</code> — TBD post-2026-06-18)</td></tr></tbody></table><p>Frontmatter format (identical across tools):</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">---</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">strictness</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">standard</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">score_threshold</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">70</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">rule_overrides</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  R01</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">max_penalty</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">-10</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }     </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># reduce vague quantifier cap from -20 to -10</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  R05</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">threshold</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">600</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># allow skills up to 600 lines instead of 500</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  R09</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">min_examples</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }      </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># require only 1 example block instead of 2</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  R10</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">suppress</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># disable model tier checking entirely</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  R23</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">budget</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">800</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }          </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># increase rules budget from 500 to 800 lines</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  R51</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">enabled</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">vocabulary_skill</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">skills/myplugin/vocabulary/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">---</span></span></code></pre></div><p><strong>Override types:</strong></p><table tabindex="0"><thead><tr><th>Type</th><th>Effect</th><th>Example</th></tr></thead><tbody><tr><td><code>suppress: true</code></td><td>Disable the rule (penalty becomes 0)</td><td><code>R10: { suppress: true }</code></td></tr><tr><td><code>enabled: true</code></td><td>Activate a rule that ships disabled by default (currently only R51)</td><td><code>R51: { enabled: true, vocabulary_skill: ... }</code></td></tr><tr><td><code>max_penalty: N</code></td><td>Cap the penalty (less negative = more lenient)</td><td><code>R01: { max_penalty: -10 }</code></td></tr><tr><td><code>threshold: N</code></td><td>Adjust numeric thresholds</td><td><code>R05: { threshold: 600 }</code></td></tr><tr><td><code>min_examples: N</code></td><td>Adjust minimum example counts</td><td><code>R09: { min_examples: 1 }</code></td></tr><tr><td><code>vocabulary_skill: &lt;path&gt;</code></td><td>Path to project&#39;s <code>vocabulary</code> skill (R51 only)</td><td><code>R51: { enabled: true, vocabulary_skill: ... }</code></td></tr></tbody></table><p>Rules not listed in <code>rule_overrides</code> use their defaults from <code>nlpm:scoring</code>. Rules that ship disabled (R51) contribute zero penalty unless <code>enabled: true</code> is set explicitly.</p><hr><h2 id="artifact-universal-tool-references" tabindex="-1">Universal Tool References <a class="header-anchor" href="#artifact-universal-tool-references" aria-label="Permalink to &quot;Universal Tool References {#artifact-universal-tool-references}&quot;">​</a></h2><p><strong>MCP tools</strong> follow the cross-tool pattern: <code>mcp__&lt;server-name&gt;__&lt;tool-name&gt;</code>. Example: <code>mcp__mermaider__validate_syntax</code>.</p><p>Per-tool built-in tool catalogs live in the overlays:</p><ul><li>Claude Code built-ins → <code>nlpm:conventions-claude</code> §16</li><li>Codex CLI built-ins → <code>nlpm:conventions-codex</code></li><li>Antigravity built-ins → <code>nlpm:conventions-antigravity</code></li></ul><hr><h2 id="scope-note" tabindex="-1">Scope Note <a class="header-anchor" href="#scope-note" aria-label="Permalink to &quot;Scope Note&quot;">​</a></h2><p>This skill covers the universal floor — conventions that apply regardless of which tool the artifact targets. It does NOT cover:</p><ul><li>Tool-specific schemas → see <code>nlpm:conventions-claude</code> / <code>nlpm:conventions-codex</code> / <code>nlpm:conventions-antigravity</code></li><li>Penalty tables → see <code>nlpm:scoring</code></li><li>Anti-patterns and best practices catalog → see <code>nlpm:patterns</code></li><li>General software engineering conventions outside NL programming artifacts</li></ul>`,71)])])}const m=t(o,[["render",n]]);export{u as __pageData,m as default};
